return [
  {
    json: {
      rules: $('Rules Creating').first().json.text,        // keep the rules
      targetValidCount: 1,      // number of validated MCQs you want
      validCount: 0,
      totalGenerated: 0,
      totalInvalid: 0,
      totalRegenerations: 0,
      questionBank: []
    }
  }
];

function safe(v, fallback = "") {
  return v === undefined || v === null || v === "" ? fallback : String(v);
}

// 1) Try to get problem from cleanedProblem
let problem = safe($json.cleanedProblem, "");

// 2) If still empty, try to recover from any raw text with [PROBLEM]...[/PROBLEM]
if (!problem || problem === "[Problem text missing]") {
  const rawSource =
    $json.problemRaw ||      // if you stored generator output here
    $json.generatorText ||   // or some custom field
    $json.text ||            // or leftover text from an earlier node
    "";

  const match = rawSource.match(/\[PROBLEM\]([\s\S]*?)\[\/PROBLEM\]/);
  if (match) {
    problem = match[1]
      .trim()
      .replace(/\\n/g, "\n");   // turn "\n" into real line breaks
  }
}

// Final fallback
problem = problem || "[Problem text missing]";

// --- Official solution from validation or fallback fields ---
const v = $json.validation || {};
const correctLabel = safe(v.officialAnswerLabel || $json.correctLabel, "[missing]");
const correctValue = safe(v.officialAnswerValue || $json.correctValue, "[missing]");
const solutionSteps = safe($json.solutionSteps, "[missing]");

// --- Solvers ---
const solver1 = safe($json.solver1Raw || $json.solver1Output, "[Solver 1 output missing]");
const solver2 = safe($json.solver2Raw || $json.solver2Output, "[Solver 2 output missing]");

// --- Validation status ---
const validFlag = v.isValid ? "VALID ✓" : "INVALID ✗";
const reason = safe(v.notes || v.reason, "[no reason provided]");

const finalText = 
`===========================================
          QUANT PROBLEM REPORT
===========================================

🟦 PROBLEM
${problem}

🟩 OFFICIAL SOLUTION
Correct Option: ${correctLabel}
Correct Value : ${correctValue}

Steps:
${solutionSteps}

🟧 SOLVER 1 — ALGEBRAIC METHOD
${solver1}

🟨 SOLVER 2 — LOGICAL / OPTION TESTING
${solver2}

🟥 VALIDATION RESULT
Status : ${validFlag}
Reason : ${reason}

===========================================
`;

return {
  ...$json,
  docText: finalText,
};

// 1. Get raw text from Validation LLM
let raw = $json.text || $json.response || "";

// 2. Clean markdown code fences if present
raw = raw.trim();

// Remove ```json and ``` wrappers if they exist
if (raw.startsWith("```")) {
  // remove starting ``` or ```json
  raw = raw.replace(/^```json\s*|^```\s*/i, "");
  // remove trailing ```
  raw = raw.replace(/```$/i, "").trim();
}

// 3. Try to parse JSON
let v;
try {
  v = JSON.parse(raw);
} catch (e) {
  v = {
    isValid: false,
    solver1MatchesOfficial: false,
    solver2MatchesOfficial: false,
    solver1MatchesSolver2: false,
    officialAnswerLabel: "",
    officialAnswerValue: "",
    notes: "Could not parse validation JSON: " + e.message + " | raw: " + raw,
  };
}

// 4. Attach parsed validation object
return {
  ...$json,
  validation: v,
};

// 1. Get raw LLM output from previous node
// In your case the text is in $json.text
let raw = $json.text || "";

// 2. Extract [PROBLEM] block (ignore INTERNAL)
const problemMatch = raw.match(/\[PROBLEM\]([\s\S]*?)\[\/PROBLEM\]/);
let problem = problemMatch ? problemMatch[1] : raw;

// 3. Clean up whitespace
problem = problem.trim();

// 4. Convert *literal* "\n" sequences to real newlines IF they exist
if (problem.includes("\\n")) {
  problem = problem.replace(/\\n/g, "\n");
}

// 5. Normalize triple+ newlines to double (optional, just for looks)
problem = problem.replace(/\n{3,}/g, "\n\n");

// 6. Return cleaned problem text
return {
  cleanedProblem: problem,
};

const raw = $json.text || "";  // solver 1 output text

function getField(label) {
  const regex = new RegExp(label + ":\\s*([\\s\\S]*?)(?:\\n\\w+:|$)");
  const m = raw.match(regex);
  return m ? m[1].trim() : "";
}

const solver1Value = getField("FinalAnswerValue");
const solver1Label = getField("ChosenOptionLabel");
const confidenceStr = getField("Confidence");
const solver1Confidence = parseInt(confidenceStr || "0", 10);

return {
  ...$json,
  solver1Raw: raw,
  solver1Value,
  solver1Label,
  solver1Confidence,
};

const raw = $json.text || "";

function getField(label) {
  const regex = new RegExp(label + ":\\s*([\\s\\S]*?)(?:\\n\\w+:|$)");
  const m = raw.match(regex);
  return m ? m[1].trim() : "";
}

const solver2Value = getField("FinalAnswerValue");
const solver2Label = getField("ChosenOptionLabel");

return {
  ...$json,
  solver2Raw: raw,
  solver2Value,
  solver2Label,
};

function toNumber(str) {
  if (!str) return NaN;
  const cleaned = String(str).replace(/[^\d./-]/g, "");
  if (cleaned.includes("/")) {
    const [a, b] = cleaned.split("/");
    const nA = parseFloat(a);
    const nB = parseFloat(b);
    if (!isNaN(nA) && !isNaN(nB) && nB !== 0) {
      return nA / nB;
    }
  }
  return parseFloat(cleaned);
}

const correctLabel = ($json.correctLabel || "").trim();      // from INTERNAL
const correctValNum = toNumber($json.correctValue);          // "240 km" -> 240

const s1Label = ($json.solver1Label || "").trim();
const s1ValNum = toNumber($json.solver1Value);

const s2Label = ($json.solver2Label || "").trim();
const s2ValNum = toNumber($json.solver2Value);

const EPS = 1e-6;

const solver1MatchesOfficial =
  s1Label === correctLabel &&
  (isNaN(correctValNum) || Math.abs(s1ValNum - correctValNum) < EPS);

const solver2MatchesOfficial =
  s2Label === correctLabel &&
  (isNaN(correctValNum) || Math.abs(s2ValNum - correctValNum) < EPS);

const solver1MatchesSolver2 =
  s1Label === s2Label &&
  (isNaN(s1ValNum) || Math.abs(s1ValNum - s2ValNum) < EPS);

const isValid = solver1MatchesOfficial && solver2MatchesOfficial && solver1MatchesSolver2;

let reason;
if (isValid) {
  reason = "Both solvers agree with the official solution.";
} else {
  reason = "Mismatch: ";
  if (!solver1MatchesOfficial) reason += "Solver 1 disagrees with official. ";
  if (!solver2MatchesOfficial) reason += "Solver 2 disagrees with official. ";
  if (!solver1MatchesSolver2) reason += "Solver 1 and Solver 2 disagree. ";
}

return {
  ...$json,
  validation: {
    isValid,
    solver1MatchesOfficial,
    solver2MatchesOfficial,
    solver1MatchesSolver2,
    normalizedCorrectLabel: correctLabel,
    normalizedCorrectValue: $json.correctValue,
    reason,
  },
};

const raw = $json.text || "";      // full generator output with [PROBLEM] and [INTERNAL]

// Extract INTERNAL block
const internalMatch = raw.match(/\[INTERNAL\]([\s\S]*?)\[\/INTERNAL\]/);
const internal = internalMatch ? internalMatch[1].trim() : "";

// Helper to grab a single-line field
function getField(label) {
  const regex = new RegExp(label + ":\\s*(.*)");
  const m = internal.match(regex);
  return m ? m[1].trim() : "";
}

// Extract fields
const correctLabel = getField("CorrectOptionLabel");
const correctValue = getField("CorrectOptionValue");
const domain = getField("Domain");

// SolutionSteps: everything after 'SolutionSteps:'
const solMatch = internal.match(/SolutionSteps:\s*([\s\S]*)$/);
const solutionSteps = solMatch ? solMatch[1].trim() : "";

return {
  ...$json,
  correctLabel,
  correctValue,
  domain,
  solutionSteps,
};

